The screen shows the p5.js Web Editor, with a file named `sketch.pjs` open. The editor displays JavaScript code for creating a swirling, colorful graphic. A canvas preview area on the right shows a red and pink spiral pattern against a dark background. The UI indicates "Auto-refresh" is enabled, and the code has been saved 25 seconds ago.

```javascript
let offset = 0;
let color1, color2, sineValue;

function setup() {
  createCanvas(400, 400);
  angleMode(DEGREES);
}

function draw() {
  background(50, 100, 150);

  sineValue = (1 + sin(frameCount)) * 128;
  color1 = color(sineValue, 0, 0);
  color2 = (1 + cos(frameCount)) * 128;

  whirligig(mouseX, mouseY, frameCount, color1, color2);
}

whirligig = function(mouseX, mouseY, frameCount, color1, color2) {
  for (let i = 0; i < 360; i++) {
    let angle = i + offset;
    let radius = 200;
    let x = mouseX + radius * cos(angle);
    let y = mouseY + radius * sin(angle);

    stroke(color1);
    strokeWeight(2.5);
    point(x, y);
  }
  offset += 1;
}
```

The console at the bottom is empty. The top bar shows tabs for "File", "Edit", "Sketch", "Help" and language selection ("English").

